package framework.agents.org.apache.manifoldcf.agents;

public class SynchronizeAll extends BaseAgentsInitializationCommand { public static final String _rcsid = "@(#)$Id: SynchronizeAll.java 988245 2010-08-23 18:39:35Z kwright $" ; public SynchronizeAll ( ) { } protected void doExecute ( IThreadContext tc ) throws ManifoldCFException { IAgentManager mgr = AgentManagerFactory . make ( tc ) ; String [ ] classnames = mgr . getAllAgents ( ) ; int i = 0 ; while ( i < classnames . length ) { String classname = classnames [ i ++ ] ; try { AgentFactory . make ( tc , classname ) ; } catch ( ManifoldCFException e ) { mgr . removeAgent ( classname ) ; } } Logging . root . info ( "Successfully synchronized all agents" ) ; } public static void main ( String [ ] args ) { if ( args . length > 0 ) { System . err . println ( "Usage: SynchronizeAll" ) ; System . exit ( 1 ) ; } try { SynchronizeAll synchronizeAll = new SynchronizeAll ( ) ; synchronizeAll . execute ( ) ; System . err . println ( "Successfully synchronized all agents" ) ; } catch ( ManifoldCFException e ) { e . printStackTrace ( ) ; System . exit ( 1 ) ; } } }